import java.sql.*;
public class PreparedParams {
    public static void main(String[] args) throws Exception {
        String sql = "SELECT * FROM users WHERE id = ? AND active = ?";
        int count = 0;
        for (char c : sql.toCharArray()) if (c == '?') count++;
        System.out.println(count);
        System.out.println(sql.contains("WHERE"));
    }
}
